import{_ as s,o as n,c as o,ai as t}from"./chunks/framework.CsYGeNYI.js";const m=JSON.parse('{"title":"系统提示词","description":"","frontmatter":{"read_when":["编辑系统提示词文本、工具列表或时间/心跳部分","更改工作区引导或 Skills 注入行为"],"summary":"OpenSoul 系统提示词包含的内容及其组装方式","title":"系统提示词","x-i18n":{"generated_at":"2026-02-03T07:46:58Z","model":"claude-opus-4-5","provider":"pi","source_hash":"bef4b2674ba0414ce28fd08a4c3ead0e0ebe989e7df3c88ca8a0b2abfec2a50b","source_path":"concepts/system-prompt.md","workflow":15}},"headers":[],"relativePath":"zh-CN/concepts/system-prompt.md","filePath":"zh-CN/concepts/system-prompt.md","lastUpdated":null}'),a={name:"zh-CN/concepts/system-prompt.md"};function l(r,e,i,p,c,d){return n(),o("div",null,[...e[0]||(e[0]=[t(`<h1 id="系统提示词" tabindex="-1"><a class="header-anchor" href="#系统提示词">#</a> 系统提示词</h1><p>OpenSoul 为每次智能体运行构建自定义系统提示词。该提示词由 <strong>OpenSoul 拥有</strong>，不使用 p-coding-agent 默认提示词。</p><p>该提示词由 OpenSoul 组装并注入到每次智能体运行中。</p><h2 id="结构" tabindex="-1"><a class="header-anchor" href="#结构">#</a> 结构</h2><p>该提示词设计紧凑，使用固定部分：</p><ul><li><strong>Tooling</strong>：当前工具列表 + 简短描述。</li><li><strong>Safety</strong>：简短的防护提醒，避免追求权力的行为或绕过监督。</li><li><strong>Skills</strong>（如果可用）：告诉模型如何按需加载 Skill 指令。</li><li><strong>OpenSoul Self-Update</strong>：如何运行 <code>config.apply</code> 和 <code>update.run</code>。</li><li><strong>Workspace</strong>：工作目录（<code>agents.defaults.workspace</code>）。</li><li><strong>Documentation</strong>：OpenSoul 文档的本地路径（仓库或 npm 包）以及何时阅读它们。</li><li><strong>Workspace Files (injected)</strong>：表示下方包含引导文件。</li><li><strong>Sandbox</strong>（启用时）：表示沙箱隔离运行时、沙箱路径，以及是否可用提权执行。</li><li><strong>Current Date &amp; Time</strong>：用户本地时间、时区和时间格式。</li><li><strong>Reply Tags</strong>：支持的提供商的可选回复标签语法。</li><li><strong>Heartbeats</strong>：心跳提示词和确认行为。</li><li><strong>Runtime</strong>：主机、操作系统、node、模型、仓库根目录（检测到时）、思考级别（一行）。</li><li><strong>Reasoning</strong>：当前可见性级别 + /reasoning 切换提示。</li></ul><p>系统提示词中的安全防护是建议性的。它们指导模型行为但不强制执行策略。使用工具策略、执行审批、沙箱隔离和渠道允许列表进行硬性执行；运维人员可以按设计禁用这些。</p><h2 id="提示词模式" tabindex="-1"><a class="header-anchor" href="#提示词模式">#</a> 提示词模式</h2><p>OpenSoul 可以为子智能体渲染更小的系统提示词。运行时为每次运行设置一个 <code>promptMode</code>（不是面向用户的配置）：</p><ul><li><code>full</code>（默认）：包含上述所有部分。</li><li><code>minimal</code>：用于子智能体；省略 <strong>Skills</strong>、<strong>Memory Recall</strong>、<strong>OpenSoul Self-Update</strong>、<strong>Model Aliases</strong>、<strong>User Identity</strong>、<strong>Reply Tags</strong>、<strong>Messaging</strong>、<strong>Silent Replies</strong> 和 <strong>Heartbeats</strong>。Tooling、<strong>Safety</strong>、Workspace、Sandbox、Current Date &amp; Time（已知时）、Runtime 和注入的上下文仍然可用。</li><li><code>none</code>：仅返回基本身份行。</li></ul><p>当 <code>promptMode=minimal</code> 时，额外注入的提示词标记为 <strong>Subagent Context</strong> 而不是 <strong>Group Chat Context</strong>。</p><h2 id="工作区引导注入" tabindex="-1"><a class="header-anchor" href="#工作区引导注入">#</a> 工作区引导注入</h2><p>引导文件被修剪后附加在 <strong>Project Context</strong> 下，这样模型无需显式读取即可看到身份和配置上下文：</p><ul><li><code>AGENTS.md</code></li><li><code>SOUL.md</code></li><li><code>TOOLS.md</code></li><li><code>IDENTITY.md</code></li><li><code>USER.md</code></li><li><code>HEARTBEAT.md</code></li><li><code>BOOTSTRAP.md</code>（仅在全新工作区上）</li></ul><p>大文件会带截断标记被截断。每个文件的最大大小由 <code>agents.defaults.bootstrapMaxChars</code> 控制（默认：20000）。缺失的文件会注入一个简短的缺失文件标记。</p><p>内部钩子可以通过 <code>agent:bootstrap</code> 拦截此步骤以修改或替换注入的引导文件（例如将 <code>SOUL.md</code> 替换为其他角色）。</p><p>要检查每个注入文件贡献了多少（原始 vs 注入、截断，加上工具 schema 开销），使用 <code>/context list</code> 或 <code>/context detail</code>。参见<a href="/docs/concepts/context">上下文</a>。</p><h2 id="时间处理" tabindex="-1"><a class="header-anchor" href="#时间处理">#</a> 时间处理</h2><p>当用户时区已知时，系统提示词包含专用的 <strong>Current Date &amp; Time</strong> 部分。为保持提示词缓存稳定，它现在只包含<strong>时区</strong>（没有动态时钟或时间格式）。</p><p>当智能体需要当前时间时使用 <code>session_status</code>；状态卡片包含时间戳行。</p><p>配置方式：</p><ul><li><code>agents.defaults.userTimezone</code></li><li><code>agents.defaults.timeFormat</code>（<code>auto</code> | <code>12</code> | <code>24</code>）</li></ul><p>完整行为详情参见<a href="/docs/date-time">日期和时间</a>。</p><h2 id="skills" tabindex="-1"><a class="header-anchor" href="#skills">#</a> Skills</h2><p>当存在符合条件的 Skills 时，OpenSoul 注入一个紧凑的<strong>可用 Skills 列表</strong>（<code>formatSkillsForPrompt</code>），其中包含每个 Skill 的<strong>文件路径</strong>。提示词指示模型使用 <code>read</code> 加载列出位置（工作区、托管或内置）的 SKILL.md。如果没有符合条件的 Skills，则省略 Skills 部分。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;available_skills&gt;</span></span>
<span class="line"><span>  &lt;skill&gt;</span></span>
<span class="line"><span>    &lt;name&gt;...&lt;/name&gt;</span></span>
<span class="line"><span>    &lt;description&gt;...&lt;/description&gt;</span></span>
<span class="line"><span>    &lt;location&gt;...&lt;/location&gt;</span></span>
<span class="line"><span>  &lt;/skill&gt;</span></span>
<span class="line"><span>&lt;/available_skills&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>这使基础提示词保持小巧，同时仍然支持有针对性的 Skill 使用。</p><h2 id="文档" tabindex="-1"><a class="header-anchor" href="#文档">#</a> 文档</h2><p>如果可用，系统提示词包含一个 <strong>Documentation</strong> 部分，指向本地 OpenSoul 文档目录（仓库工作区中的 <code>docs/</code> 或打包的 npm 包文档），并注明公共镜像、源仓库、社区 Discord 和 ClawHub (<a href="https://clawhub.com" target="_blank" rel="noreferrer">https://clawhub.com</a>) 用于 Skills 发现。提示词指示模型首先查阅本地文档了解 OpenSoul 行为、命令、配置或架构，并尽可能自己运行 <code>opensoul status</code>（仅在无法访问时询问用户）。</p>`,29)])])}const u=s(a,[["render",l]]);export{m as __pageData,u as default};
